import tkinter as tkfrom tkinter import ttk, messageboximport matplotlib.pyplot as pltfrom matplotlib.backends.backend_tkagg import FigureCanvasTkAggfrom itertools import permutationsimport pandas as pd#Default-----------------------------------------------------------------------prize_pool = 350places_payed = 15first_percentage = 0.3#these will be used as a baseline for the distributions. Change later#quick % calculator for working out a fixed 1st place as a percentage----------def as_percent(target_amount, prizepool = prize_pool):    as_p = target_amount/prize_pool        return as_p#Distribution functions--------------------------------------------------------def distribution_1(prizes = prize_pool,players = places_payed,first = first_percentage,slope=0.5):    distribution = []    payout = first        for i in range (0, players):        place = (f"{i+1}",prizes * payout)        distribution.append(place)        payout = payout*slope            return distributiondef distribution_2(prizes = prize_pool, players = places_payed, first = first_percentage):    distribution =[]    total = prizes        for i in range(0,players):        amount_won = total * first        distribution.append((f"{i+1}", amount_won))        total = total - amount_won        return distributiondef distribution_3(prizes = prize_pool, players = places_payed, first = first_percentage, slope = 0.05):    distribution = []    winning_percentage = first_percentage        for i in range(0, players):        amount_won = prizes*winning_percentage        distribution.append((f"{i+1}", amount_won))        winning_percentage = winning_percentage - slope        return distributiondef distribution_4(prizes = prize_pool, players = places_payed, first = first_percentage):    distribution = []    winning_percentage = first_percentage    slope = 1/players        for i in range(0, players):        amount_won = prizes*winning_percentage        distribution.append((f"{i+1}", amount_won))        winning_percentage = winning_percentage - slope        return distribution#ICM calculator----------------------------------------------------------------players = [1,2,3]stacks = [1000, 2000, 3000]payouts = [100, 50, 30]players_and_stacks = [("reg", 1000), ("fish", 2000), ("whale", 3000)]def Stack_size_chop(players = players, stacks = stacks, payouts=payouts):    #create a table for the min payout    current_players = []    for i in players:        current_players.append([f"{i}",min(payouts)])    #create payout share based on stack size    prize_pool_sub_min = sum(payouts) - len(players)*min(payouts)    for i,j in enumerate(stacks):        player_payout = j/sum(stacks)*prize_pool_sub_min        current_players[i][1] += player_payout            return current_players#before we can calculate a true icm chop we need to have a function that calculate player probabilitiesdef icm_prob(place, players = players_and_stacks):    target_name, target_stack = players[0]    total_chips = sum(stack for _, stack in players)    stacks_by_name = {name: stack for name, stack in players}    if place == 1:        return target_stack / total_chips    other_names = [name for name, _ in players[1:]]    probability = 0.0    for seq in permutations(other_names, place - 1):        remaining_total = total_chips        term = 1.0        for name in seq:            term *= stacks_by_name[name] / remaining_total            remaining_total -= stacks_by_name[name]        term *= target_stack / remaining_total        probability += term    return probabilitydef icm_chop(payouts = payouts, players = players_and_stacks):    player_names = []    player_prize =[]        min_cash = min(payouts)        for name, stack in players:        player_names.append(name)                player_ev = min_cash        for place in range(1, len(players)+1):            ordered_players = [(name, stack)] + [                (n, s) for n, s in players if n != name            ]            player_ev += icm_prob(place, ordered_players)*(payouts[place -1 ] - min_cash)                    player_prize.append(player_ev)         payout_data_frame = pd.DataFrame({        "Name": player_names,        "Prize": player_prize    })            return payout_data_frame#GUI (ft ChatGPT)--------------------------------------------------------------class PrizePoolApp:    def __init__(self, root):        self.root = root        self.root.title("Prize Pool Visualiser")        self.root.geometry("1150x750")        # Dark mode colors        self.bg_color = "#1e1e1e"        self.panel_color = "#252526"        self.widget_color = "#2d2d30"        self.text_color = "#ffffff"        self.accent_color = "#3a86ff"        self.border_color = "#3c3c3c"        self.setup_dark_theme()        # Main root background        self.root.configure(bg=self.bg_color)        # Control frame        control_frame = ttk.Frame(root, padding=10, style="Dark.TFrame")        control_frame.pack(side=tk.LEFT, fill=tk.Y)        ttk.Label(control_frame, text="Prize Pool", style="Dark.TLabel").grid(row=0, column=0, sticky="w", pady=5)        self.prize_pool_entry = ttk.Entry(control_frame, style="Dark.TEntry")        self.prize_pool_entry.insert(0, str(prize_pool))        self.prize_pool_entry.grid(row=0, column=1, pady=5)        ttk.Label(control_frame, text="Places Paid", style="Dark.TLabel").grid(row=1, column=0, sticky="w", pady=5)        self.places_paid_entry = ttk.Entry(control_frame, style="Dark.TEntry")        self.places_paid_entry.insert(0, str(places_payed))        self.places_paid_entry.grid(row=1, column=1, pady=5)        ttk.Label(control_frame, text="1st Place %", style="Dark.TLabel").grid(row=2, column=0, sticky="w", pady=5)        self.first_percentage_entry = ttk.Entry(control_frame, style="Dark.TEntry")        self.first_percentage_entry.insert(0, str(first_percentage))        self.first_percentage_entry.grid(row=2, column=1, pady=5)        ttk.Label(control_frame, text="Slope", style="Dark.TLabel").grid(row=3, column=0, sticky="w", pady=5)        self.slope_entry = ttk.Entry(control_frame, style="Dark.TEntry")        self.slope_entry.insert(0, "0.5")        self.slope_entry.grid(row=3, column=1, pady=5)        ttk.Label(control_frame, text="Distribution Type", style="Dark.TLabel").grid(row=4, column=0, sticky="w", pady=5)        self.dist_var = tk.StringVar(value="distribution_1")        self.dist_menu = ttk.Combobox(            control_frame,            textvariable=self.dist_var,            values=["distribution_1", "distribution_2", "distribution_3", "distribution_4"],            state="readonly",            style="Dark.TCombobox"        )        self.dist_menu.grid(row=4, column=1, pady=5)        ttk.Button(control_frame, text="Generate Chart", command=self.update_chart, style="Dark.TButton").grid(            row=5, column=0, columnspan=2, pady=10, sticky="ew"        )        ttk.Button(control_frame, text="Clear Output", command=self.clear_output, style="Dark.TButton").grid(            row=6, column=0, columnspan=2, pady=5, sticky="ew"        )        ttk.Button(control_frame, text="Open Chop Calculator", command=self.open_chop_window, style="Dark.TButton").grid(            row=7, column=0, columnspan=2, pady=6, sticky="ew"        )        ttk.Separator(control_frame, orient="horizontal").grid(row=8, column=0, columnspan=2, sticky="ew", pady=8)        ttk.Label(control_frame, text="Quick Percentage Calculator", style="Dark.TLabel").grid(            row=9, column=0, columnspan=2, sticky="w", pady=(0, 3)        )        ttk.Label(control_frame, text="Target Amount", style="Dark.TLabel").grid(row=10, column=0, sticky="w", pady=3)        self.target_amount_entry = ttk.Entry(control_frame, style="Dark.TEntry")        self.target_amount_entry.insert(0, "100")        self.target_amount_entry.grid(row=10, column=1, pady=3)        ttk.Button(control_frame, text="Calculate %", command=self.calculate_percentage, style="Dark.TButton").grid(            row=11, column=0, columnspan=2, pady=3, sticky="ew"        )        self.percentage_result_var = tk.StringVar(value="Percentage: ")        ttk.Label(control_frame, textvariable=self.percentage_result_var, style="Dark.TLabel").grid(            row=12, column=0, columnspan=2, sticky="w", pady=3        )        ttk.Label(control_frame, text="Payouts", style="Dark.TLabel").grid(            row=13, column=0, columnspan=2, sticky="w", pady=(8, 3)        )        self.output_text = tk.Text(            control_frame,            width=35,            height=16,            bg=self.widget_color,            fg=self.text_color,            insertbackground=self.text_color,            relief="flat",            highlightthickness=1,            highlightbackground=self.border_color        )        self.output_text.grid(row=14, column=0, columnspan=2, pady=3)        # Chart frame        chart_frame = ttk.Frame(root, padding=10, style="Dark.TFrame")        chart_frame.pack(side=tk.RIGHT, fill=tk.BOTH, expand=True)        self.fig, self.ax = plt.subplots(figsize=(8, 5))        self.fig.patch.set_facecolor(self.panel_color)        self.ax.set_facecolor(self.widget_color)        self.canvas = FigureCanvasTkAgg(self.fig, master=chart_frame)        self.canvas.get_tk_widget().pack(fill=tk.BOTH, expand=True)        self.update_chart()    def setup_dark_theme(self):        style = ttk.Style()        style.theme_use("clam")        style.configure("Dark.TFrame", background=self.bg_color)        style.configure("Dark.TLabel", background=self.bg_color, foreground=self.text_color)        style.configure(            "Dark.TButton",            background=self.widget_color,            foreground=self.text_color,            borderwidth=1,            focusthickness=0,            padding=6        )        style.map(            "Dark.TButton",            background=[("active", self.accent_color)],            foreground=[("active", self.text_color)]        )        style.configure(            "Dark.TEntry",            fieldbackground=self.widget_color,            foreground=self.text_color,            bordercolor=self.border_color,            insertcolor=self.text_color        )        style.configure(            "Dark.TCombobox",            fieldbackground=self.widget_color,            background=self.widget_color,            foreground=self.text_color,            arrowcolor=self.text_color,            bordercolor=self.border_color        )        self.root.option_add("*TCombobox*Listbox.background", self.widget_color)        self.root.option_add("*TCombobox*Listbox.foreground", self.text_color)        self.root.option_add("*TCombobox*Listbox.selectBackground", self.accent_color)        self.root.option_add("*TCombobox*Listbox.selectForeground", self.text_color)    def apply_dark_to_window(self, window):        window.configure(bg=self.bg_color)    def clear_output(self):        self.output_text.delete("1.0", tk.END)        self.percentage_result_var.set("Percentage: ")    def get_inputs(self):        try:            prizes = float(self.prize_pool_entry.get())            players = int(self.places_paid_entry.get())            first = float(self.first_percentage_entry.get())            slope = float(self.slope_entry.get())            if prizes <= 0:                raise ValueError("Prize pool must be greater than 0.")            if players <= 0:                raise ValueError("Places paid must be greater than 0.")            if first < 0:                raise ValueError("1st place percentage cannot be negative.")            return prizes, players, first, slope        except ValueError as e:            messagebox.showerror("Input Error", str(e))            return None    def generate_distribution(self, prizes, players, first, slope):        dist_type = self.dist_var.get()        if dist_type == "distribution_1":            return distribution_1(prizes, players, first, slope)        elif dist_type == "distribution_2":            return distribution_2(prizes, players, first)        elif dist_type == "distribution_3":            return distribution_3(prizes, players, first, slope)        elif dist_type == "distribution_4":            return distribution_4(prizes, players, first)        return []    def calculate_percentage(self):        try:            prizepool = float(self.prize_pool_entry.get())            target_amount = float(self.target_amount_entry.get())            if prizepool <= 0:                raise ValueError("Prize pool must be greater than 0.")            result = as_percent(target_amount, prizepool) * 100            self.percentage_result_var.set(f"Percentage: {result:.2f}%")        except ValueError as e:            messagebox.showerror("Calculation Error", str(e))    def update_chart(self):        inputs = self.get_inputs()        if inputs is None:            return        prizes, players, first, slope = inputs        distribution = self.generate_distribution(prizes, players, first, slope)        places = [place for place, amount in distribution]        amounts = [amount for place, amount in distribution]        self.ax.clear()        self.ax.set_facecolor(self.widget_color)        self.fig.patch.set_facecolor(self.panel_color)        bars = self.ax.bar(places, amounts)        for bar in bars:            bar.set_edgecolor("white")        self.ax.set_title("Prize Pool Distribution", color=self.text_color)        self.ax.set_xlabel("Place", color=self.text_color)        self.ax.set_ylabel("Payout", color=self.text_color)        self.ax.tick_params(axis="x", rotation=45, colors=self.text_color)        self.ax.tick_params(axis="y", colors=self.text_color)        for spine in self.ax.spines.values():            spine.set_color(self.text_color)        self.fig.tight_layout()        self.canvas.draw()        self.output_text.delete("1.0", tk.END)        total_paid = 0        for place, amount in distribution:            self.output_text.insert(tk.END, f"Place {place}: {amount:.2f}\n")            total_paid += amount        self.output_text.insert(tk.END, f"\nTotal paid out: {total_paid:.2f}\n")        self.output_text.insert(tk.END, f"Prize pool: {prizes:.2f}\n")        self.output_text.insert(tk.END, f"Difference: {prizes - total_paid:.2f}\n")    def open_chop_window(self):        chop_window = tk.Toplevel(self.root)        chop_window.title("Chop Calculator")        chop_window.geometry("800x550")        self.apply_dark_to_window(chop_window)        main_frame = ttk.Frame(chop_window, padding=10, style="Dark.TFrame")        main_frame.pack(fill=tk.BOTH, expand=True)        ttk.Label(main_frame, text="Chop Type", style="Dark.TLabel").grid(row=0, column=0, sticky="w", padx=10, pady=10)        chop_type_var = tk.StringVar(value="icm_chop")        chop_menu = ttk.Combobox(            main_frame,            textvariable=chop_type_var,            values=["icm_chop", "stack_size_chop"],            state="readonly",            width=20,            style="Dark.TCombobox"        )        chop_menu.grid(row=0, column=1, sticky="w", padx=10, pady=10)        ttk.Label(main_frame, text="Player Names (comma separated)", style="Dark.TLabel").grid(            row=1, column=0, sticky="w", padx=10, pady=5        )        names_entry = ttk.Entry(main_frame, width=50, style="Dark.TEntry")        names_entry.insert(0, "reg,fish,whale")        names_entry.grid(row=1, column=1, padx=10, pady=5)        ttk.Label(main_frame, text="Stacks (comma separated)", style="Dark.TLabel").grid(            row=2, column=0, sticky="w", padx=10, pady=5        )        stacks_entry = ttk.Entry(main_frame, width=50, style="Dark.TEntry")        stacks_entry.insert(0, "1000,2000,3000")        stacks_entry.grid(row=2, column=1, padx=10, pady=5)        ttk.Label(main_frame, text="Payouts (comma separated)", style="Dark.TLabel").grid(            row=3, column=0, sticky="w", padx=10, pady=5        )        payouts_entry = ttk.Entry(main_frame, width=50, style="Dark.TEntry")        payouts_entry.insert(0, "100,50,30")        payouts_entry.grid(row=3, column=1, padx=10, pady=5)        ttk.Label(main_frame, text="Results", style="Dark.TLabel").grid(row=4, column=0, sticky="nw", padx=10, pady=(10, 5))        result_text = tk.Text(            main_frame,            width=70,            height=20,            bg=self.widget_color,            fg=self.text_color,            insertbackground=self.text_color,            relief="flat",            highlightthickness=1,            highlightbackground=self.border_color        )        result_text.grid(row=4, column=1, padx=10, pady=(10, 5))        def run_chop():            try:                names = [name.strip() for name in names_entry.get().split(",") if name.strip()]                stack_values = [float(x.strip()) for x in stacks_entry.get().split(",") if x.strip()]                payout_values = [float(x.strip()) for x in payouts_entry.get().split(",") if x.strip()]                if not names:                    raise ValueError("Enter at least one player name.")                if len(names) != len(stack_values):                    raise ValueError("Player names and stacks must have the same number of values.")                if len(payout_values) == 0:                    raise ValueError("Enter at least one payout.")                if any(s <= 0 for s in stack_values):                    raise ValueError("All stacks must be greater than 0.")                result_text.delete("1.0", tk.END)                selected = chop_type_var.get()                if selected == "icm_chop":                    players_and_stacks_local = list(zip(names, stack_values))                    result_df = icm_chop(payouts=payout_values, players=players_and_stacks_local)                    result_text.insert(tk.END, "ICM Chop Results\n")                    result_text.insert(tk.END, "-" * 40 + "\n")                    for _, row in result_df.iterrows():                        result_text.insert(tk.END, f"{row['Name']}: {row['Prize']:.2f}\n")                    result_text.insert(tk.END, f"\nTotal: {result_df['Prize'].sum():.2f}\n")                elif selected == "stack_size_chop":                    result = Stack_size_chop(players=names, stacks=stack_values, payouts=payout_values)                    result_text.insert(tk.END, "Stack Size Chop Results\n")                    result_text.insert(tk.END, "-" * 40 + "\n")                    total = 0                    for player_name, prize in result:                        result_text.insert(tk.END, f"{player_name}: {prize:.2f}\n")                        total += prize                    result_text.insert(tk.END, f"\nTotal: {total:.2f}\n")            except ValueError as e:                messagebox.showerror("Chop Calculation Error", str(e))        ttk.Button(main_frame, text="Calculate Chop", command=run_chop, style="Dark.TButton").grid(            row=5, column=0, columnspan=2, padx=10, pady=15, sticky="ew"        )# Run app-----------------------------------------------------------------------if __name__ == "__main__":    root = tk.Tk()    app = PrizePoolApp(root)    root.mainloop()